"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[91361],{73544:(e,i,a)=>{a.r(i),a.d(i,{data:()=>n});const n={key:"v-a7a1e752",path:"/mongodb/%E6%95%99%E7%A8%8B/%E9%85%8D%E7%BD%AE/%E8%AE%BE%E7%BD%AE%E7%94%A8%E6%88%B7%E5%AF%86%E7%A0%81.html",title:"MongoDB 设置用户名密码",lang:"zh-CN",frontmatter:{},excerpt:"",headers:[{level:2,title:"超级管理员",slug:"超级管理员",children:[{level:3,title:"设置 admin",slug:"设置-admin",children:[]},{level:3,title:"开启验证",slug:"开启验证",children:[]},{level:3,title:"重启 MongoDB",slug:"重启-mongodb",children:[]},{level:3,title:"登录数据库",slug:"登录数据库",children:[]}]},{level:2,title:"添加数据库用户",slug:"添加数据库用户",children:[]},{level:2,title:"常用命令",slug:"常用命令",children:[]},{level:2,title:"MongoDB 数据库默认角色",slug:"mongodb-数据库默认角色",children:[]}],git:{updatedTime:1653451151e3,contributors:[{name:"panzhiyue",email:"30484534+panzhiyue@users.noreply.github.com",commits:1}]},filePathRelative:"mongodb/教程/配置/设置用户密码.md"}},11317:(e,i,a)=>{a.r(i),a.d(i,{default:()=>o});var n=a(57293);const d=(0,n.uE)('<h1 id="mongodb-设置用户名密码" tabindex="-1"><a class="header-anchor" href="#mongodb-设置用户名密码" aria-hidden="true">#</a> MongoDB 设置用户名密码</h1><p>转自:https://www.jianshu.com/p/237a0c5ad9fa</p><blockquote><ol><li>MongoDB 版本 v4.0.5</li><li>系统 Win10</li></ol></blockquote><h2 id="超级管理员" tabindex="-1"><a class="header-anchor" href="#超级管理员" aria-hidden="true">#</a> 超级管理员</h2><h3 id="设置-admin" tabindex="-1"><a class="header-anchor" href="#设置-admin" aria-hidden="true">#</a> 设置 admin</h3><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code>use admin  \ndb.createUser({\n  user: &#39;admin&#39;,  // 用户名\n  pwd: &#39;123456&#39;,  // 密码\n  roles:[{\n    role: &#39;root&#39;,  // 角色\n    db: &#39;admin&#39;  // 数据库\n  }]\n})\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>设置完成，可以输入 <code>show users</code> 查看是否设置成功。</p><h3 id="开启验证" tabindex="-1"><a class="header-anchor" href="#开启验证" aria-hidden="true">#</a> 开启验证</h3><p>找到 MongoDB 安装目录，打开 <code>mongod.cfg</code>文件，找到以下这句：</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code>#security:\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>修改为：</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code>security:\n  authorization: enabled\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="重启-mongodb" tabindex="-1"><a class="header-anchor" href="#重启-mongodb" aria-hidden="true">#</a> 重启 MongoDB</h3><p>打开任务管理器</p><p><img src="https:////upload-images.jianshu.io/upload_images/1128764-564fe60c63ce951b.jpg?imageMogr2/auto-orient/strip|imageView2/2/w/788/format/webp" alt="img"></p><p>任务管理器界面</p><p>找到 MongoDB 服务，右键重新启动。</p><p>这时，我们可以打开 powershell 连接数据库：</p><p>输入 mongo：</p><p><img src="https:////upload-images.jianshu.io/upload_images/1128764-08b60c7bdc8e9010.jpg?imageMogr2/auto-orient/strip|imageView2/2/w/657/format/webp" alt="img"></p><p>截图</p><p>显示连接成功，但是当我们输入其他指令时，会提示没有权限：</p><p><img src="https:////upload-images.jianshu.io/upload_images/1128764-5b9c49021375919b.jpg?imageMogr2/auto-orient/strip|imageView2/2/w/622/format/webp" alt="img"></p><h3 id="登录数据库" tabindex="-1"><a class="header-anchor" href="#登录数据库" aria-hidden="true">#</a> 登录数据库</h3><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code>// 方式一\nmongo\nuse admin\ndb.auth(&#39;admin&#39;, &#39;123456&#39;)\n\n// 方式二\nmongo admin -u admin -p 123456\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>这时候我们就可以正常访问和操作数据了。</p><h2 id="添加数据库用户" tabindex="-1"><a class="header-anchor" href="#添加数据库用户" aria-hidden="true">#</a> 添加数据库用户</h2><p>我们除了可以设置数据库的超级管理员以外，还可以给每个数据库设置单独的管理员。其只有操作单独数据的一定权限。</p><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code>use test  // 跳转到需要添加用户的数据库\ndb.createUser({\n  user: &#39;fooadmin&#39;,  // 用户名\n  pwd: &#39;123456&#39;,  // 密码\n  roles:[{\n    role: &#39;readWrite&#39;,  // 角色\n    db: &#39;test&#39;  // 数据库名\n  }]\n})\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="常用命令" tabindex="-1"><a class="header-anchor" href="#常用命令" aria-hidden="true">#</a> 常用命令</h2><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code>show users  // 查看当前库下的用户\n\ndb.dropUser(&#39;testadmin&#39;)  // 删除用户\n\ndb.updateUser(&#39;admin&#39;, {pwd: &#39;654321&#39;})  // 修改用户密码\n\ndb.auth(&#39;admin&#39;, &#39;654321&#39;)  // 密码认证\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="mongodb-数据库默认角色" tabindex="-1"><a class="header-anchor" href="#mongodb-数据库默认角色" aria-hidden="true">#</a> MongoDB 数据库默认角色</h2><ol><li>数据库用户角色：read、readWrite</li><li>数据库管理角色：dbAdmin、dbOwner、userAdmin</li><li>集群管理角色：clusterAdmin、clusterManager、clusterMonitor、hostManager</li><li>备份恢复角色：backup、restore</li><li>所有数据库角色： readAnyDatabase、readWriteAnyDatabase、userAdminAnyDatabase、 dbAdminAnyDatabase</li><li>超级用户角色：root</li></ol>',33),s={href:"https://links.jianshu.com/go?to=https%3A%2F%2Fdocs.mongodb.com%2Fmanual%2Fcore%2Fsecurity-built-in-roles%2F",target:"_blank",rel:"noopener noreferrer"},l=(0,n.Uk)("更多细节参考官方文档"),r={},o=(0,a(63243).Z)(r,[["render",function(e,i){const a=(0,n.up)("ExternalLinkIcon");return(0,n.wg)(),(0,n.iD)(n.HY,null,[d,(0,n._)("p",null,[(0,n._)("a",s,[l,(0,n.Wm)(a)])])],64)}]])},63243:(e,i)=>{i.Z=(e,i)=>{const a=e.__vccOpts||e;for(const[e,n]of i)a[e]=n;return a}}}]);